import { launch } from '@lib/frontend/platform/utils/launch/launch';
import type { LaunchModel } from '@lib/frontend/platform/utils/launch/launch..models';
import { withTest } from '@lib/shared/testing/utils/withTest/withTest';

const { displayName } = withTest({ target: () => launch });

describe(displayName, () => {
  let platform: LaunchModel;

  beforeAll(async () => {
    platform = await launch();
  });

  test('works', async () => {
    const x = await platform.open('https://www.google.com');
    expect(1).toStrictEqual(1);
  });

  afterAll(async () => {
    await platform.close();
  });
});
